import React, { useState, useEffect, useRef } from 'react';

const images = [
  '/images/login-1.jpg',
  '/images/login-2.jpg',
  '/images/chat-screen-1.jpg',
  '/images/outcoming-1.jpg',
  '/images/outcoming-2.jpg',
];

function TechGlobeSection() {
  const [currentImage, setCurrentImage] = useState(0);
  const [showImg, setShowImg] = useState(true);
  const [vidIndex, setVidIndex] = useState(0);
  const v1 = useRef(null);
  const v2 = useRef(null);

  useEffect(() => {
    const id = setInterval(() => {
      setShowImg(false);
      setTimeout(() => {
        setCurrentImage(p => (p + 1) % images.length);
        setShowImg(true);
      }, 500);
    }, 2500);
    return () => clearInterval(id);
  }, []);

  function onV1End() {
    setVidIndex(1);
    setTimeout(() => {
      if (v2.current) { v2.current.currentTime = 0; v2.current.play().catch(() => {}); }
    }, 100);
  }

  function onV2Time() {
    if (v2.current && v2.current.currentTime >= 4) {
      v2.current.pause();
      setVidIndex(0);
      setTimeout(() => {
        if (v1.current) { v1.current.currentTime = 0; v1.current.play().catch(() => {}); }
      }, 100);
    }
  }

  return (
    <section className="py-20 px-4 sm:px-6 lg:px-8 bg-white overflow-hidden">
      <style>{`
        @keyframes rvIn { from { clip-path: inset(50% 50% 50% 50% round 16px); } to { clip-path: inset(0 0 0 0 round 16px); } }
        @keyframes rvOut { from { clip-path: inset(0 0 0 0 round 16px); } to { clip-path: inset(50% 50% 50% 50% round 16px); } }
      `}</style>
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold text-gray-900 mb-4">Sản Phẩm Của Chúng Tôi</h2>
          <p className="text-gray-500 text-lg">Xem demo trực tiếp sản phẩm đã triển khai</p>
        </div>

        {/* Sphere background container */}
        <div className="relative flex items-center justify-center" style={{ minHeight: '560px' }}>

          {/* Agora-style sphere */}
          <div className="absolute pointer-events-none" style={{ width: '900px', height: '900px', top: '50%', left: '50%', transform: 'translate(-50%, -50%)' }}>
            <div className="absolute inset-0 rounded-full" style={{
              background: 'radial-gradient(circle at 40% 35%, rgba(15, 20, 50, 0.95) 0%, rgba(8, 10, 30, 0.98) 45%, rgba(5, 5, 20, 0.95) 70%, transparent 100%)',
            }} />
            <div className="absolute inset-6 rounded-full" style={{
              background: 'radial-gradient(circle at 35% 30%, rgba(56, 97, 251, 0.04) 0%, transparent 50%)',
              border: '1px solid rgba(255,255,255,0.03)',
            }} />
            <div className="absolute inset-0 rounded-full opacity-30" style={{
              backgroundImage: 'radial-gradient(rgba(255,255,255,0.12) 1px, transparent 1px)',
              backgroundSize: '14px 14px',
              mask: 'radial-gradient(circle, black 25%, transparent 65%)',
              WebkitMask: 'radial-gradient(circle, black 25%, transparent 65%)',
            }} />
            <div className="absolute inset-12 rounded-full" style={{
              background: 'conic-gradient(from 180deg, transparent 0%, rgba(100, 80, 220, 0.04) 8%, transparent 16%)',
            }} />
          </div>

          {/* Content on top of sphere */}
          <div className="relative z-10 flex flex-col lg:flex-row gap-8 items-center justify-center w-full">
            {/* Video side */}
            <div className="w-full lg:w-3/5">
              <div style={{ display: vidIndex === 0 ? 'block' : 'none' }}>
                <div className="rounded-2xl overflow-hidden" style={{ aspectRatio: '16/9', background: '#000', boxShadow: '0 20px 60px rgba(0,0,0,0.4)' }}>
                  <video ref={v1} className="w-full h-full object-cover" autoPlay muted playsInline onEnded={onV1End} src="/videos/video-laptop.mp4" />
                </div>
              </div>
              <div className="flex justify-center" style={{ display: vidIndex === 1 ? 'flex' : 'none' }}>
                <div className="rounded-2xl overflow-hidden" style={{ aspectRatio: '9/16', height: '500px', background: '#000', boxShadow: '0 20px 60px rgba(0,0,0,0.4)' }}>
                  <video ref={v2} className="w-full h-full object-cover" muted playsInline onTimeUpdate={onV2Time} src="/videos/send-images.mp4" />
                </div>
              </div>
            </div>

            {/* Image side */}
            <div className="w-full lg:w-2/5 flex justify-center">
              <div style={{ width: '260px', height: '520px', position: 'relative' }}>
                <img
                  src={images[currentImage]}
                  alt="App screenshot"
                  className="w-full h-full object-cover rounded-2xl"
                  style={{
                    animation: showImg ? 'rvIn 0.5s ease-out forwards' : 'rvOut 0.4s ease-in forwards',
                    boxShadow: '0 20px 60px rgba(0,0,0,0.4)',
                  }}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default TechGlobeSection;
